
package com.example.taxgap.domain.entity; import com.example.taxgap.domain.enums.Severity; import jakarta.persistence.*; import java.time.*;
@Entity @Table(name="exception_records")
public class ExceptionRecord { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; private String transactionId; private String customerId; private String ruleName; @Enumerated(EnumType.STRING) private Severity severity; @Column(length=1000) private String message; private LocalDateTime createdAt = LocalDateTime.now();
 public Long getId(){return id;} public void setId(Long v){id=v;} public String getTransactionId(){return transactionId;} public void setTransactionId(String v){transactionId=v;} public String getCustomerId(){return customerId;} public void setCustomerId(String v){customerId=v;} public String getRuleName(){return ruleName;} public void setRuleName(String v){ruleName=v;} public Severity getSeverity(){return severity;} public void setSeverity(Severity v){severity=v;} public String getMessage(){return message;} public void setMessage(String v){message=v;} public LocalDateTime getCreatedAt(){return createdAt;} public void setCreatedAt(LocalDateTime v){createdAt=v;} }
